param(    [Parameter(ValueFromRemainingArguments = $true)]    [string[]]$NpmArgs)$ErrorActionPreference = "Stop"$Root = Resolve-Path (Join-Path $PSScriptRoot "..")$NpmCli = Join-Path $Root "frontend\.tools\npm\package\bin\npm-cli.js"if (-not (Test-Path $NpmCli)) {    throw "Local npm cli not found at $NpmCli. Run the frontend dependency bootstrap again."}$NodeExe = $env:NODE_EXEif ($NodeExe -and -not (Test-Path $NodeExe)) {    throw "NODE_EXE is set but does not point to an existing Node.js executable: $NodeExe"}if (-not $NodeExe) {    $NodeCommand = Get-Command node -ErrorAction SilentlyContinue    if (-not $NodeCommand) {        throw "Node.js was not found. Install Node.js LTS or set NODE_EXE to a Node.js executable."    }    $NodeExe = $NodeCommand.Source}& $NodeExe $NpmCli @NpmArgsexit $LASTEXITCODE